// game.js — WeChat Mini Game entry point
// Generated by MiniGameBackend

console.log('[game.js] Requiring adapter...');
var adapter = require('./adapter.js');
var firstScreen = require('./first-screen');
console.log('[game.js] Adapter and first-screen loaded');

// Create single canvas for WebGL
var canvas = wx.createCanvas();
adapter.setup(canvas);
firstScreen.start(canvas);
console.log('[game.js] Canvas created and splash drawn', canvas.width, 'x', canvas.height);

// Helper: load subpackage with error handling
function loadSubpackage(name) {
    if (typeof wx.loadSubpackage !== 'function') {
        console.log('[game.js] wx.loadSubpackage not available, skipping ' + name);
        return Promise.resolve();
    }
    return new Promise(function(resolve) {
        wx.loadSubpackage({
            name: name,
            success: function() {
                console.log('[game.js] Subpackage "' + name + '" loaded');
                resolve();
            },
            fail: function(err) {
                console.log('[game.js] Subpackage "' + name + '" load issue:', err.errMsg || err);
                resolve();
            }
        });
    });
}

async function startGame() {
    try {
        // Phase 1: Load engine and assets in parallel
        console.log('[game.js] Loading engine and assets in parallel...');
        await Promise.all([
            loadSubpackage('engine'),
            loadSubpackage('assets')
        ]);
        console.log('[game.js] Engine and assets subpackages loaded');

        // Phase 2: Preload assets from filesystem into memory
        console.log('[game.js] Preloading assets...');
        await adapter.preloadAssets(function(loaded, total) {
            firstScreen.setProgress(loaded / total);
        });
        console.log('[game.js] Assets preloaded, count:', globalThis.__preloadedAssets ? Object.keys(globalThis.__preloadedAssets).length : 0);

        // Phase 3: Wait for engine to initialize (Gdx bridge set by gdx.wasm.js)
        console.log('[game.js] Waiting for engine initialization...');
        var gdxWaitStart = Date.now();
        while (typeof window.Gdx === 'undefined') {
            if (Date.now() - gdxWaitStart > 30000) {
                throw new Error('Timed out waiting for Gdx to initialize (30s)');
            }
            await new Promise(function(r) { setTimeout(r, 50); });
        }
        console.log('[game.js] window.Gdx available, type:', typeof window.Gdx);

        // Phase 4: Load game code subpackage
        console.log('[game.js] Loading game code subpackage...');
        await loadSubpackage('game');
        console.log('[game.js] Game code subpackage loaded');

        // Phase 5: Start the compiled game via globalThis bridge
        var mainModule = globalThis.__gameApp;
        if (mainModule && mainModule.main) {
            console.log('[game.js] Calling main()...');
            mainModule.main(["${mainClassArgs}"]);
            console.log('[game.js] main() returned');
        } else {
            console.error('[game.js] ERROR: __gameApp not available, cannot call main()');
        }

        // Redraw splash to bridge canvas resize gap
        firstScreen.redraw();
    } catch (err) {
        console.error('[game.js] FAILED:', err);
    }
}

startGame();
